import{_ as a}from"./chunks/subs-usage-warning.Bdji-M7h.js";import{_ as t,o as n,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Run a Cleanup","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/cleanup.md","filePath":"subscriptions/cleanup.md"}'),s={name:"subscriptions/cleanup.md"};function r(l,e,u,h,c,d){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="run-a-cleanup" tabindex="-1">Run a Cleanup <a class="header-anchor" href="#run-a-cleanup" aria-label="Permalink to &quot;Run a Cleanup&quot;">​</a></h1><p>When you&#39;re close to a <a href="./../getting-started/glossary.html#quota--limit">quota</a> — or already over one — the fastest fix is often to remove things you no longer need. The tracker helps by <strong>suggesting</strong> what to clean up and giving you a <strong>cleanup action</strong> to run. This guide covers both.</p><p><strong>Who can run cleanup:</strong> Supreme Admin, King, Alliance Leader, and Co-Leader (anyone with the cleanup ability for their scope). Alliance Players cannot.</p><h2 id="where-cleanup-lives" tabindex="-1">Where cleanup lives <a class="header-anchor" href="#where-cleanup-lives" aria-label="Permalink to &quot;Where cleanup lives&quot;">​</a></h2><p>Cleanup is part of your <strong>Subscription &amp; Usage panel</strong> — the kingdom detail page (Kings), the <a href="./../how-to/my-alliance.html">My Alliance</a> page (Leaders and Co-Leaders), or the platform manager (Supreme Admins). When usage is high, the panel shows <strong>cleanup suggestions</strong> alongside the resource bars.</p><p><img src="'+a+'" alt="Usage panel with cleanup suggestions"></p><h2 id="reading-the-suggestions" tabindex="-1">Reading the suggestions <a class="header-anchor" href="#reading-the-suggestions" aria-label="Permalink to &quot;Reading the suggestions&quot;">​</a></h2><p>For premium scopes, the panel can recommend likely things to remove to get you back under a limit — for example, old imports or unused records taking up space. Treat these as <strong>suggestions</strong>, not automatic deletions: they point you at candidates, and you decide.</p><h2 id="running-a-cleanup" tabindex="-1">Running a cleanup <a class="header-anchor" href="#running-a-cleanup" aria-label="Permalink to &quot;Running a cleanup&quot;">​</a></h2><ol><li>Open your Subscription &amp; Usage panel.</li><li>Review the cleanup suggestions and warnings.</li><li>Use the <strong>cleanup action</strong> to clear out what&#39;s safe to remove, or remove specific items yourself (for example, deleting old imports — see the imports and recycle-bin guides).</li></ol><p>Because most deletes in the app are <strong><a href="./../getting-started/glossary.html#soft-delete">soft deletes</a></strong> (they go to the Recycle Bin, not gone forever), cleaning up is low-risk — you can usually restore something if you change your mind. Note, though, that items sitting in the Recycle Bin may still count toward some limits until they&#39;re purged; see <a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a> and the <a href="./../how-to/recycle-bin.html">Recycle Bin</a> guide.</p><h2 id="cleanup-and-limited-mode" tabindex="-1">Cleanup and limited mode <a class="header-anchor" href="#cleanup-and-limited-mode" aria-label="Permalink to &quot;Cleanup and limited mode&quot;">​</a></h2><p>If a hard limit was reached and your scope dropped into <strong>limited (cleanup) mode</strong>, cleanup is exactly how you get out of it. Once you free up enough that usage falls back under the safe threshold, the restriction lifts. The full details of limited mode — including that it can lift automatically after you clean up — are in <a href="./suspension.html">Suspension &amp; Limited Mode</a>.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./quota-warnings.html">Quota Warnings</a> — understanding the warning levels first.</li><li><a href="./suspension.html">Suspension &amp; Limited Mode</a> — how cleanup ends a limited-mode restriction.</li><li><a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a> — why cleanup is reversible.</li></ul>',15)])])}const f=t(s,[["render",r]]);export{m as __pageData,f as default};
